import{_ as r,o as e,c as a,ag as d}from"./chunks/framework.OsDJF_Ea.js";const i="/docs/modules/drum-machine.png",p=JSON.parse('{"title":"Drum Machine","description":"","frontmatter":{},"headers":[],"relativePath":"modules/drum-machine.md","filePath":"modules/drum-machine.md"}'),o={name:"modules/drum-machine.md"};function n(s,t,u,h,c,l){return e(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="drum-machine" tabindex="-1">Drum Machine <a class="header-anchor" href="#drum-machine" aria-label="Permalink to &quot;Drum Machine&quot;">​</a></h1><p><strong>Category:</strong> Sound Sources</p><p>4-voice electronic drum synthesizer with kick, snare, hi-hat, and percussion. Each voice has layered sound design (sub-oscillator, click transient, noise). MIDI triggerable using GM drum mapping. Uses 2 hardware banks: Bank 1 for trigger/pitch (hold 1s for voice edit), Bank 2 for volume/mute.</p><img src="'+i+'" alt="drum-machine module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>kick_trig</strong></td><td>Triggers the kick voice. Connect from Button, Sequencer, or Clock.</td></tr><tr><td><strong>snare_trig</strong></td><td>Triggers the snare voice.</td></tr><tr><td><strong>hat_trig</strong></td><td>Triggers the hi-hat voice.</td></tr><tr><td><strong>perc_trig</strong></td><td>Triggers the percussion voice.</td></tr><tr><td><strong>note</strong></td><td>MIDI note input for GM drum mapping (kick=36, snare=38, hat=42, perc=45). Connect from MIDIIn.</td></tr><tr><td><strong>gate</strong></td><td>Gate signal paired with note input.</td></tr><tr><td><strong>velocity</strong></td><td>MIDI velocity 0-1. Scales hit intensity.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>mixL</strong> (audio)</td><td>Stereo mix of all voices, left.</td></tr><tr><td><strong>mixR</strong> (audio)</td><td>Stereo mix right.</td></tr><tr><td><strong>auxL</strong> (audio)</td><td>Auxiliary send mix left. Route to Reverb or Delay.</td></tr><tr><td><strong>auxR</strong> (audio)</td><td>Auxiliary send mix right.</td></tr><tr><td><strong>kickL</strong> (audio)</td><td>Individual kick output left. Enable &#39;show individual outputs&#39;.</td></tr><tr><td><strong>kickR</strong> (audio)</td><td>Individual kick output right.</td></tr><tr><td><strong>snareL</strong> (audio)</td><td>Individual snare left.</td></tr><tr><td><strong>snareR</strong> (audio)</td><td>Individual snare right.</td></tr><tr><td><strong>hatL</strong> (audio)</td><td>Individual hi-hat left.</td></tr><tr><td><strong>hatR</strong> (audio)</td><td>Individual hi-hat right.</td></tr><tr><td><strong>percL</strong> (audio)</td><td>Individual percussion left.</td></tr><tr><td><strong>percR</strong> (audio)</td><td>Individual percussion right.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Connect a Clock to a Sequencer, then wire gate outputs to trigger inputs for a basic beat. Use aux sends to route snare/hat to shared Reverb while keeping kick dry. Hold trigger button 1s to enter the sub-menu for per-layer tweaking.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const m=r(o,[["render",n]]);export{p as __pageData,m as default};
